mapper.select:
select account_id, open_id, homepage_id, password, name, email, mphone, phone, company, provider_id
from account
where open_id=#{openId}

select count(*) as cnt from account
where open_id=#{openId}
  and replace(replace(mphone, '-', ''), ' ', '') = replace(replace(#{phone}, '-', ''), ' ', '')

SELECT a.account_id, a.open_id, a.homepage_id, a.password, a.name, a.email, a.mphone, a.phone, a.company, a.provider_id
FROM account a
JOIN provider p ON a.provider_id = p.provider_id
WHERE p.provider_name = #{providerName}
  AND a.open_id = #{openId}

SELECT account_id, open_id, homepage_id, password, name, email, mphone, phone, company, provider_id
FROM account
WHERE account_id = #{accountId}

mapper.update:
UPDATE account
SET name = #{name}, email = #{email}, mphone = #{mphone}, phone = #{phone}, company = #{company}
WHERE account_id = #{accountId}
